={
  "model": "claude-sonnet-4-20250514",
  "max_tokens": 1024,
  "messages": [
    {
      "role": "user",
      "content": "You are an AI triage agent for ArcVault, a B2B software company. Analyze the following customer message and return a JSON object.

Message source: {{ $json.source }}
Message: {{ $json.raw_message }}

Classify and extract the following:

1. category: exactly one of: Bug Report, Feature Request, Billing Issue, Technical Question, Incident/Outage
2. priority: exactly one of: Low, Medium, High
3. confidence_score: integer 0-100 representing how confident you are in the category classification
4. issue_summary: one sentence describing the core issue
5. identifiers: array of objects with "type" and "value" for any account IDs, invoice numbers, error codes, URLs, or other identifiers mentioned. If none found, return empty array.
6. urgency_signal: exactly one of: Low, Medium, High — based on language urgency, user impact, and business impact in the message
7. summary: a 2-3 sentence human-readable summary suitable for the receiving team

Respond with ONLY valid JSON, no markdown, no explanation. Use this exact structure:
{
  "category": "",
  "priority": "",
  "confidence_score": 0,
  "issue_summary": "",
  "identifiers": [{"type": "", "value": ""}],
  "urgency_signal": "",
  "summary": ""
}"
    }
  ]
}

parameters.jsCode:
const inputData = $('Sample Inputs').item.json;
const response = $input.item.json;

// Extract text from Claude's response
let text = response.content[0].text;

// Clean up in case Claude wraps JSON in markdown fences
text = text.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

// Parse the JSON from Claude
const parsed = JSON.parse(text);

// Build the final record using our schema
const record = {
  message_id: inputData.message_id,
  source: inputData.source,
  raw_message: inputData.raw_message,
  classification: {
    category: parsed.category,
    priority: parsed.priority,
    confidence_score: parsed.confidence_score
  },
  enrichment: {
    issue_summary: parsed.issue_summary,
    identifiers: parsed.identifiers || [],
    urgency_signal: parsed.urgency_signal
  },
  routing: {
    destination_queue: "",
    escalation: {
      flagged: false,
      reasons: []
    }
  },
  summary: parsed.summary,
  processed_at: new Date().toISOString()
};

return { json: record };

const record = { ...$input.item.json };

// Map categories to destination queues
const routingMap = {
  "Bug Report": "Engineering",
  "Feature Request": "Product",
  "Billing Issue": "Billing",
  "Technical Question": "IT/Security",
  "Incident/Outage": "Engineering"
};

const category = record.classification.category;
record.routing.destination_queue = routingMap[category] || "General Support";

return { json: record };

const record = { ...$input.item.json };
const reasons = [];

// Rule 1: Low confidence
if (record.classification.confidence_score < 70) {
  reasons.push("Confidence score below 70%");
}

// Rule 2: Outage/downtime keywords
const msg = record.raw_message.toLowerCase();
const outageKeywords = ["outage", "down for all", "multiple users affected", "stopped loading", "stopped working"];
for (const keyword of outageKeywords) {
  if (msg.includes(keyword)) {
    reasons.push(`Outage keyword detected: "${keyword}"`);
    break;
  }
}

// Rule 3: Billing discrepancy over $500
const billingMatch = msg.match(/\$[\d,]+/g);
if (billingMatch && record.classification.category === "Billing Issue") {
  const amounts = billingMatch.map(a => parseFloat(a.replace(/[$,]/g, '')));
  if (amounts.length >= 2) {
    const diff = Math.abs(amounts[0] - amounts[1]);
    if (diff > 500) {
      reasons.push(`Billing discrepancy of $${diff} exceeds $500 threshold`);
    }
  }
}

// Apply escalation
if (reasons.length > 0) {
  record.routing.escalation.flagged = true;
  record.routing.escalation.reasons = reasons;
  record.routing.destination_queue = "Escalation";
}

return { json: record };

const allRecords = $input.all().map(item => item.json);

const output = {
  pipeline: "ArcVault Intake Triage",
  generated_at: new Date().toISOString(),
  total_records: allRecords.length,
  escalated_count: allRecords.filter(r => r.routing.escalation.flagged).length,
  records: allRecords
};

return [{ json: output }];
